// =====================================================
// BUILD EMAIL PAYLOAD — Forge Confirmation (LINK-based PDF) + App credentials
// Routes by product (FW/FC/FFM/FAI). Adds the Forge App access block + OTP line
// to every cohort. Password = Firstname@Forge! (same as the app account).
// =====================================================

const input  = $input.first().json;
const body   = input.body || input;
const fields = body.fields || body.lead || body;

const product = String(fields.product || '').toUpperCase().trim();
const email   = fields.email_1 || fields.email || '';
const name    = (fields.name || fields.first_name || '').trim() || 'there';
const amount  = fields.amount || '15000';
const phone   = fields.phone || fields.phone_number || fields.mobile || '';

// ── Forge App credentials (same Firstname@Forge! the account uses) ──
const APP_URL   = 'https://app.forgebylevelup.com/auth';
const firstRaw  = name.split(/\s+/)[0] || 'there';
const firstName = firstRaw.charAt(0).toUpperCase() + firstRaw.slice(1).toLowerCase();
const password  = `${firstName}@Forge!`;

const APP_ACCESS = `
<div style="background:#f6f6f4;border:1px solid #e5e5e5;border-radius:10px;padding:16px 20px;margin:20px 0;">
  <p style="margin:0 0 8px;"><strong>Your Forge App access</strong></p>
  <p style="margin:0 0 10px;">The Forge App is your command center — learning, community, your roadmap and full journey, all in one place. Your account is ready:</p>
  <p style="margin:0;">&#128279; Login: <a href="${APP_URL}">${APP_URL}</a><br>&#128231; Email: <strong>${email}</strong><br>&#128273; Password: <strong>${password}</strong></p>
  <p style="margin:10px 0 0;font-size:13px;color:#555;">Prefer not to type a password? You can also log in with a one-time OTP sent to your registered phone number${phone ? ' (' + phone + ')' : ''} — just tap &ldquo;Login with OTP&rdquo; on the login screen. You can change your password anytime after your first login.</p>
</div>`;

const WA_GROUP = 'https://chat.whatsapp.com/LQRc2E2SzyMJUkKw6oBnSR';

function driveLink(fileId) {
  return `https://drive.google.com/file/d/${fileId}/view?usp=sharing`;
}

const PROGRAM_CONFIG = {
  'FW': {
    contentName: 'forge_writing',
    programName: 'The Forge Writing Retreat',
    pdfLink:     driveLink('11AhrwRQNXQXSsp7sSZJRdh-yokb-Kk0B'),
    subject:     'Welcome to The Forge Writing Retreat — Your Seat is Confirmed',
    body: `<p>Dear {{name}},</p>
<p>Welcome to The Forge Writing Retreat, a space built for stories that have been waiting too long to be told. Congratulations, your seat is officially confirmed!</p>
<p>Your confirmation payment has secured your place among a circle of screenwriters, authors, and storytellers who've chosen to step away from distraction and dive deep into their story. Over the residency, you'll reconnect with your voice, write stories that move, heal, and transform.</p>
<p>At the Forge, we believe that writing is more than putting words on a page; it's a journey inward. You'll spend your days surrounded by nature, meaningful conversations, and fellow writers who understand what it means to create from a place of honesty and courage.</p>
<p><strong>Here's what happens next</strong></p>
<p><strong>Your Welcome Guide</strong><br>We've prepared a Welcome Guide that walks you through what to expect — from your daily schedule and workshops to glimpses of the magical experience that awaits you. <a href="{{pdfLink}}">Click here to view your Welcome Guide</a>. It's the beginning of your next great chapter.</p>
<p><strong>Join the Inner Circle</strong><br>You're now part of the LevelUp Inner Circle, a creative family of writers, filmmakers, and storytellers who support each other's journeys long after the retreat ends. You'll also get access to online writing sessions, community discussions, and exclusive alumni events.</p>
<p><strong>Balance Payment</strong><br>Details regarding your balance payment, venue and dates will be shared with you in the next email, so stay tuned.</p>
<p>Here's your community WhatsApp group: <a href="${WA_GROUP}">Join the Forge Community</a></p>
<p>You'll also be added to your respective Edition WhatsApp Group closer to the start of the retreat, where all updates and details will be shared.</p>
<p>If you have any questions or need support, feel free to reach out anytime:<br>Email: <a href="mailto:forge@leveluplearning.in">forge@leveluplearning.in</a><br>WhatsApp: Hiresh — 9840203604 (Program Lead) | Pranaush — 7397468193 (Head of Admissions)</p>
<p>Writers often say that the Forge changed the way they look at their stories — and helped them discover a writing process they still use to this day.</p>
<p>Welcome home, Writer. Your story begins now.</p>
<p>With warmth and excitement,<br>Team Forge by LevelUp Learning.</p>`
  },
  'FFM': {
    contentName: 'forge_fm',
    programName: 'The Forge Filmmaking Bootcamp',
    pdfLink:     driveLink('1RgognN9YiEg0zVa1akMrBKcjEkSyUgwM'),
    subject:     'Welcome to The Forge Filmmaking Bootcamp — Your Seat is Confirmed',
    body: `<p>Dear {{name}},</p>
<p>Welcome to The Forge Filmmaking Bootcamp! Congratulations, your seat is officially confirmed!</p>
<p>Your confirmation payment has locked in your spot, and you're now part of a tribe of dreamers-turned-doers who are about to live, breathe, and create cinema together.</p>
<p>At Forge, you don't just learn filmmaking, you live it. From script to screen, you'll write, direct, shoot, and edit your very own short film alongside passionate creators from across the country. Over fifteen days online and offline, you'll collaborate, experiment, and tell stories that you have always wanted, and in the process, discover what it truly means to be a filmmaker.</p>
<p><strong>Here's what happens next</strong></p>
<p><strong>Your Welcome Guide</strong><br>We've prepared a Welcome Guide that walks you through what to expect at the bootcamp, from your daily schedule to a sneak peek of the experience that awaits you. <a href="{{pdfLink}}">Click here to view your Welcome Guide</a>. Trust us, it will get you excited!</p>
<p><strong>Join the Inner Circle</strong><br>You're now part of the LevelUp Inner Circle, your private creator community where you'll connect with mentors, alumni, and your batchmates — collaborators who'll stay with you long after the bootcamp ends. And also get access to our online community discussions and workshops, along with invites to exclusive events and productions.</p>
<p><strong>Balance Payment</strong><br>Details regarding your balance payment, venue and dates will be shared with you in the next email, so stay tuned.</p>
<p>Here's the link to the Community WhatsApp Group: <a href="${WA_GROUP}">Join the Forge Community</a></p>
<p>Don't worry, you will also be added to the Edition WhatsApp Group closer to the start of the program, where all the updates and info will be shared.</p>
<p>Now, if you have any more doubts regarding what's next or anything else for that matter, feel free to reach out to us:<br>Email: <a href="mailto:forge@leveluplearning.in">forge@leveluplearning.in</a><br>WhatsApp: Hiresh — 9840203604 (Program Lead) | Pranaush — 7397468193 (Head of Admissions)</p>
<p>Our Alumni refer to the Forge as a once-in-a-lifetime experience, so brace yourself!</p>
<p>And get ready to Lights, Camera, and Forge!</p>
<p>Your Loudest Cheerleader,<br>Team Forge by LevelUp Learning.</p>`
  },
  'FAI': {
    contentName: 'forge_ai',
    programName: 'the Forge AI Residency',
    pdfLink:     driveLink('1ugijAt2bwHptkPcop8GswXYHBYRpwIAc'),
    subject:     'Welcome to the Forge AI Residency — Your Seat is Confirmed',
    body: `<p>Dear {{name}},</p>
<p>Welcome to the Forge AI Residency, a space built for the people who are done watching AI happen and ready to start building with it. Congratulations, your seat is officially confirmed!</p>
<p>Your confirmation payment has secured your place among a small group of founders, marketers, and operators who have chosen to step into the biggest shift of our decade. Over the residency, you will stop consuming content about AI and start using it to ship real things — real products, real automations, real work that lives beyond the week.</p>
<p>At the Forge, we believe AI is not a tool you learn. It is a way of working you adopt. You will spend your days surrounded by practitioners, fellow builders, and a room engineered for focus, where every hour is spent learning, building, and shipping alongside people who are taking this just as seriously as you are.</p>
<p><strong>Here is what happens next:</strong></p>
<p><strong>Your Welcome Guide</strong><br>We have prepared a Welcome Guide that walks you through what to expect, from your daily schedule and build sessions to the experience that awaits you. <a href="{{pdfLink}}">Click here to view your Welcome Guide</a>. It is the start of how you adapt to what is coming.</p>
<p><strong>Join the Inner Circle</strong><br>You are now part of the LevelUp Inner Circle, a community of founders, builders, and operators who support each other long after the residency ends. You will also get access to online sessions, community discussions, and exclusive alumni events.</p>
<p>Here is your community WhatsApp group: <a href="${WA_GROUP}">Join the Forge Community</a></p>
<p>You will also be added to your respective Edition WhatsApp Group closer to the start of the residency, where all updates and prep will be shared.</p>
<p><strong>Balance Payment</strong><br>Details regarding your balance payment, venue, and dates will be shared with you in the next email, so stay tuned.</p>
<p>If you have any questions or need support, reach out anytime:<br>Email: <a href="mailto:forge@leveluplearning.in">forge@leveluplearning.in</a><br>WhatsApp: Hiresh — 9840203604 (Program Lead) | Sashank — 7338992170 (Head of Admissions)</p>
<p>Builders often tell us that the Forge changed how they think about what is possible for them, and helped them adopt a way of working with AI that they still use every single day.</p>
<p>Welcome to the Forge, Builder. The shift starts now.</p>
<p>With warmth and excitement,<br>Team Forge by LevelUp Learning.</p>`
  },
  'FC': {
    contentName: 'forge_creators',
    programName: 'The Forge Creator Residency',
    pdfLink:     driveLink('1aBArF-HuL8Uc4QUYGXqySnWEaewsDxwh'),
    subject:     'Welcome to The Forge Creator Residency — Your Seat is Confirmed',
    body: `<p>Dear {{name}},</p>
<p>Welcome to The Forge Creator Residency!</p>
<p>Congratulations, your seat is officially confirmed!</p>
<p>Your confirmation payment has locked in your spot, and you're now part of a tribe of creators and founders who are about to transform their social media presence and build powerful personal brands together.</p>
<p>At Forge, you don't just learn content creation, you live it. From strategy to execution, you'll develop your unique voice, craft compelling content, and grow your audience alongside ambitious creators and founders from across the country.</p>
<p>Over the residency program, you'll collaborate, experiment, and build the personal brand you've always envisioned, and in the process, discover what it truly means to be a creator in today's digital landscape.</p>
<p><strong>Here's what happens next:</strong></p>
<p><strong>Your Welcome Guide</strong><br>We've prepared a Welcome Guide that walks you through what to expect at the residency, from your daily schedule to a sneak peek of the experience that awaits you. <a href="{{pdfLink}}">Click here to view your Welcome Guide</a>. Trust us, it will get you excited!</p>
<p><strong>Join the Inner Circle</strong><br>You're now part of the LevelUp Inner Circle, your private creator community where you'll connect with mentors, alumni, and your cohort — collaborators who'll stay with you long after the residency ends. Get access to our online community discussions and workshops, along with invites to exclusive events and collaborations.</p>
<p><strong>Balance Payment</strong><br>Details regarding your balance payment, venue, and dates will be shared with you in the next email, so stay tuned.</p>
<p>Here's the link to the Community WhatsApp Group: <a href="${WA_GROUP}">Join the Forge Community</a></p>
<p>Don't worry, you will also be added to the Cohort WhatsApp Group closer to the start of the program, where all the updates and info will be shared.</p>
<p>Now, if you have any doubts regarding what's next or anything else for that matter, feel free to reach out to us:<br>Email: <a href="mailto:forge@leveluplearning.in">forge@leveluplearning.in</a><br>WhatsApp: Hiresh — 9840203604 (Program Lead) | Sashank — 7338992170 (Head of Admissions)</p>
<p>Our Alumni refer to the Forge as a once-in-a-lifetime experience, so brace yourself!</p>
<p>Get ready to create, connect, and Forge your path!</p>
<p>Your Loudest Cheerleader,<br>Team Forge by LevelUp Learning.</p>`
  }
};

const config = PROGRAM_CONFIG[product];
if (!config) {
  throw new Error('Forge Confirmation Email: unsupported product code: ' + product + '. Configured: FW, FC, FFM, FAI.');
}
if (!email) {
  throw new Error('Forge Confirmation Email: missing email_1 in webhook body.');
}

function replacePlaceholders(text) {
  return String(text)
    .replace(/\{\{name\}\}/g, name)
    .replace(/\{\{programName\}\}/g, config.programName)
    .replace(/\{\{pdfLink\}\}/g, config.pdfLink)
    .replace(/\{\{amount\}\}/g, amount);
}

// Build the body, then inject the Forge App access block right after the
// "Welcome Guide" paragraph (uniform across all cohorts).
let bodyHtml = replacePlaceholders(config.body);
const marker = 'Welcome Guide</a>';
const mIdx = bodyHtml.indexOf(marker);
if (mIdx !== -1) {
  const pEnd = bodyHtml.indexOf('</p>', mIdx);
  const at = pEnd !== -1 ? pEnd + 4 : bodyHtml.length;
  bodyHtml = bodyHtml.slice(0, at) + APP_ACCESS + bodyHtml.slice(at);
} else {
  bodyHtml = bodyHtml + APP_ACCESS;
}

return [{
  json: {
    productCode: product,
    contentName: config.contentName,
    programName: config.programName,
    pdfLink:     config.pdfLink,
    toEmail:     email,
    toName:      name,
    phone:       phone,
    password:    password,
    subject:     replacePlaceholders(config.subject),
    bodyHtml:    bodyHtml,
    amount:      amount
  }
}];

// Build one audit-log row from the Build payload + the onboarding response.
const b = $('Build Email Payload').first().json;
let onboarded = 'n/a';
try {
  const r = $('Onboard Student').first().json || {};
  onboarded = r.status || r.error || 'n/a';
} catch (e) { onboarded = 'n/a'; }

return [{ json: {
  'Timestamp':  new Date().toISOString().replace('T', ' ').slice(0, 19),
  'Email':      b.toEmail    || '',
  'Name':       b.toName     || '',
  'Product':    b.productCode || '',
  'Program':    b.programName || '',
  'Amount':     b.amount     || '',
  'Password':   b.password   || '',
  'Onboarded':  onboarded,
  'EmailSent':  'sent',
  'Subject':    b.subject    || ''
}}];
